'alevel-bio-biodiversity': `<svg viewBox="0 0 400 300" xmlns="http://www.w3.org/2000/svg"><defs><style>@keyframes bd_g{0%,100%{opacity:.5}50%{opacity:1}}.bd_a{animation:bd_g 2s ease-in-out infinite}.bd_b{animation:bd_g 2s ease-in-out infinite .5s}.bd_c{animation:bd_g 2s ease-in-out infinite 1s}.bd_d{animation:bd_g 2s ease-in-out infinite 1.5s}</style></defs><circle class="bd_a" cx="120" cy="120" r="30" fill="var(--accent)" fill-opacity=".2" stroke="var(--accent)" stroke-width="1.8"/><circle class="bd_b" cx="200" cy="100" r="22" fill="var(--text-dim)" fill-opacity=".2" stroke="var(--text-dim)" stroke-width="1.8"/><circle class="bd_c" cx="280" cy="130" r="26" fill="var(--accent)" fill-opacity=".15" stroke="var(--accent)" stroke-width="1.8"/><circle class="bd_d" cx="160" cy="190" r="35" fill="var(--text-dim)" fill-opacity=".15" stroke="var(--text-dim)" stroke-width="1.8"/><text x="120" y="124" font-size="7" fill="var(--text-dim)" font-family="sans-serif" text-anchor="middle">species 1</text><text x="200" y="104" font-size="7" fill="var(--text-dim)" font-family="sans-serif" text-anchor="middle">species 2</text><text x="280" y="134" font-size="7" fill="var(--text-dim)" font-family="sans-serif" text-anchor="middle">species 3</text><text x="160" y="194" font-size="7" fill="var(--text-dim)" font-family="sans-serif" text-anchor="middle">species 4</text><rect x="50" y="235" width="300" height="40" rx="6" fill="var(--surface)" stroke="var(--border)" stroke-width="1.5"/><text x="200" y="252" font-size="7" fill="var(--text-dim)" font-family="sans-serif" text-anchor="middle">Simpson's Index D = 1 − Σ(n/N)²</text><text x="200" y="267" font-size="7" fill="var(--text-dim)" font-family="sans-serif" text-anchor="middle">higher D → greater biodiversity</text><text x="200" y="24" font-size="11" fill="var(--text)" font-family="sans-serif" font-weight="bold" text-anchor="middle">Biodiversity &amp; Conservation</text></svg>`,

